input.new_string:
const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export function runScenario(scenario: Scenario): ScenarioResult {
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const item = step.items[0];
      const base = BASE_PREMIUMS[item.type];
      const premium = Math.ceil(base * 1.1) + 5;
      return { premium };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
}

