import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office — quote", () => {
  it("quotes a single sword for a brand-new customer (base + first-insurance surcharge + processing fee)", () => {
    const output = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    // Base sword premium 100 G; first-insurance surcharge +10% → 110; +5 G processing fee → 115 G.
    expect(output).toEqual({ results: [{ premium: 115 }] });
  });
  it("quotes each main item type at its base premium (amulet, staff, potion)", () => {
    const amulet = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }] }],
    });
    // 60 × 1.10 (first insurance) = 66 → +5 fee = 71
    expect(amulet).toEqual({ results: [{ premium: 71 }] });

    const staff = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff", material: "oak", enchantment: 0, cursed: false }] }],
    });
    // 80 × 1.10 = 88 → +5 fee = 93
    expect(staff).toEqual({ results: [{ premium: 93 }] });

    const potion = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }] }],
    });
    // 40 × 1.10 = 44 → +5 fee = 49
    expect(potion).toEqual({ results: [{ premium: 49 }] });
  });
  it.todo("quotes a single component at 25 G base premium");
  it.todo("quotes a block of 3 alike components at the 60 G special base premium");
  it.todo("adds a 50% surcharge for a cursed item");
  it.todo("adds a 30% surcharge for an item with enchantment >= 5");
  it.todo("applies a 20% loyalty discount for customers with >= 2 years of business");
  it.todo("applies a 15% discount on contracts after the customer's first");
  it.todo("rounds the premium up (in MHPCO's favor)");
});

describe("MHPCO Claim Office — claim", () => {
  it.todo("pays out claim amount minus 100 G deductible per incident");
  it.todo("pays out 0 (not negative) when the deductible exceeds the damage");
  it.todo("reimburses items with enchantment >= 8 at only 50% of damage");
  it.todo("fully reimburses items made of dragon material");
  it.todo("caps cumulative payout at twice the insurance sum");
});

describe("MHPCO Claim Office — scenarios", () => {
  it.todo("handles the schema example 1 (single quote)");
  it.todo("handles the schema example 2 (quote followed by two claims) with correct remainingCap");
});

