const COMPONENT_BASE = 25;
const COMPONENT_BLOCK_BASE = 60;
const COMPONENT_BLOCK_SIZE = 3;

function basePremiumOf(items: Item[]): number {
  const counts = new Map<string, number>();
  for (const it of items) {
    counts.set(it.type, (counts.get(it.type) ?? 0) + 1);
  }
  let total = 0;
  for (const [type, count] of counts) {
    const base = BASE_PREMIUMS[type];
    if (base === COMPONENT_BASE) {
      const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
      const remainder = count - blocks * COMPONENT_BLOCK_SIZE;
      total += blocks * COMPONENT_BLOCK_BASE + remainder * COMPONENT_BASE;
    } else {
      total += base * count;
    }
  }
  return total;
}

export function runScenario(scenario: Scenario): ScenarioResult {
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const base = basePremiumOf(step.items);
      const premium = ceilGold(base * FIRST_INSURANCE_SURCHARGE) + PROCESSING_FEE;
      return { premium };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
}

