import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office — quote", () => {
  it("quotes a single sword for a brand-new customer (base + first-insurance surcharge + processing fee)", () => {
    const output = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    // Base sword premium 100 G; first-insurance surcharge +10% → 110; +5 G processing fee → 115 G.
    expect(output).toEqual({ results: [{ premium: 115 }] });
  });
  it("quotes each main item type at its base premium (amulet, staff, potion)", () => {
    const amulet = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }] }],
    });
    // 60 × 1.10 (first insurance) = 66 → +5 fee = 71
    expect(amulet).toEqual({ results: [{ premium: 71 }] });

    const staff = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff", material: "oak", enchantment: 0, cursed: false }] }],
    });
    // 80 × 1.10 = 88 → +5 fee = 93
    expect(staff).toEqual({ results: [{ premium: 93 }] });

    const potion = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }] }],
    });
    // 40 × 1.10 = 44 → +5 fee = 49
    expect(potion).toEqual({ results: [{ premium: 49 }] });
  });
  it("quotes a single component at 25 G base premium", () => {
    const output = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune", material: "stone", enchantment: 0, cursed: false }],
        },
      ],
    });
    // 25 × 1.10 = 27.5 → ceil 28 → +5 fee = 33
    expect(output).toEqual({ results: [{ premium: 33 }] });
  });
  it("quotes a block of 3 alike components at the 60 G special base premium", () => {
    const output = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune", material: "stone", enchantment: 0, cursed: false },
            { type: "rune", material: "stone", enchantment: 0, cursed: false },
            { type: "rune", material: "stone", enchantment: 0, cursed: false },
          ],
        },
      ],
    });
    // 3 alike components form a block: 60 G × 1.10 first = 66 → +5 fee = 71
    expect(output).toEqual({ results: [{ premium: 71 }] });
  });
  it("adds a 50% surcharge for a cursed item", () => {
    const output = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }] },
      ],
    });
    // sword 100 × 1.50 cursed = 150 → × 1.10 first = 165 → +5 fee = 170
    expect(output).toEqual({ results: [{ premium: 170 }] });
  });
  it("adds a 30% surcharge for an item with enchantment >= 5", () => {
    const output = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }] },
      ],
    });
    // sword 100 × 1.30 high-enchant = 130 → × 1.10 first = 143 → +5 fee = 148
    expect(output).toEqual({ results: [{ premium: 148 }] });
  });
  it("applies a 20% loyalty discount for customers with >= 2 years of business", () => {
    const output = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
      ],
    });
    // 100 × 0.80 loyalty × 1.10 first = 88 → +5 fee = 93
    expect(output).toEqual({ results: [{ premium: 93 }] });
  });
  it("applies a 15% discount on contracts after the customer's first", () => {
    const output = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
      ],
    });
    // Step 0 (first contract): 100 × 1.10 = 110 → +5 = 115
    // Step 1 (subsequent contract): 100 × 0.85 = 85 → +5 = 90
    expect(output).toEqual({ results: [{ premium: 115 }, { premium: 90 }] });
  });
  it("rounds the premium up (in MHPCO's favor)", () => {
    const output = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
        { op: "quote", items: [{ type: "staff", material: "oak", enchantment: 0, cursed: false }] },
      ],
    });
    // Step 1: staff 80 × 0.80 loyalty × 0.85 subsequent = 54.4 → must round UP to 55 → +5 fee = 60
    expect(output.results[1]).toEqual({ premium: 60 });
  });
});

describe("MHPCO Claim Office — claim", () => {
  it.todo("pays out claim amount minus 100 G deductible per incident");
  it.todo("pays out 0 (not negative) when the deductible exceeds the damage");
  it.todo("reimburses items with enchantment >= 8 at only 50% of damage");
  it.todo("fully reimburses items made of dragon material");
  it.todo("caps cumulative payout at twice the insurance sum");
});

describe("MHPCO Claim Office — scenarios", () => {
  it.todo("handles the schema example 1 (single quote)");
  it.todo("handles the schema example 2 (quote followed by two claims) with correct remainingCap");
});

export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export type QuoteStep = { op: "quote"; items: Item[] };
export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export type QuoteResult = { premium: number };
export type ClaimResult = { payout: number; remainingCap: number };
export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioResult {
  results: StepResult[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 1.1;
const CURSED_SURCHARGE = 1.5;
const HIGH_ENCHANT_SURCHARGE = 1.3;
const HIGH_ENCHANT_THRESHOLD = 5;
const LOYALTY_DISCOUNT = 0.8;
const LOYALTY_THRESHOLD = 2;
const SUBSEQUENT_CONTRACT_DISCOUNT = 0.85;

// Round up to whole G "in MHPCO's favor", tolerating FP error from percentage math.
function ceilGold(amount: number): number {
  return Math.ceil(Math.round(amount * 1000) / 1000);
}

const COMPONENT_BASE = 25;
const COMPONENT_BLOCK_BASE = 60;
const COMPONENT_BLOCK_SIZE = 3;

function itemRiskFactor(item: Item): number {
  let factor = 1;
  if (item.cursed) factor *= CURSED_SURCHARGE;
  if ((item.enchantment ?? 0) >= HIGH_ENCHANT_THRESHOLD) factor *= HIGH_ENCHANT_SURCHARGE;
  return factor;
}

function basePremiumOf(items: Item[]): number {
  const groups = new Map<string, Item[]>();
  for (const it of items) {
    const list = groups.get(it.type) ?? [];
    list.push(it);
    groups.set(it.type, list);
  }
  let total = 0;
  for (const [type, group] of groups) {
    const base = BASE_PREMIUMS[type];
    if (base === COMPONENT_BASE) {
      const blocks = Math.floor(group.length / COMPONENT_BLOCK_SIZE);
      const remainder = group.length - blocks * COMPONENT_BLOCK_SIZE;
      total += blocks * COMPONENT_BLOCK_BASE + remainder * COMPONENT_BASE;
    } else {
      for (const it of group) {
        total += base * itemRiskFactor(it);
      }
    }
  }
  return total;
}

function computeQuotePremium(items: Item[], customer: Customer, contractIndex: number): number {
  let amount = basePremiumOf(items);
  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD) amount *= LOYALTY_DISCOUNT;
  amount *= contractIndex === 0 ? FIRST_INSURANCE_SURCHARGE : SUBSEQUENT_CONTRACT_DISCOUNT;
  return ceilGold(amount) + PROCESSING_FEE;
}

export function runScenario(scenario: Scenario): ScenarioResult {
  const customer = scenario.customer;
  let contractIndex = 0;
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const premium = computeQuotePremium(step.items, customer, contractIndex);
      contractIndex++;
      return { premium };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
}

